   1 | // Pass byteOffset + byteLength explicitly so the round-trip survives
   2 | // Node's Buffer pool. Buffer.from(b64, "base64") returns a slice of a
   3 | // shared 8KB pool (poolSize), and `new Float32Array(buf.buffer)` ignores
   4 | // the slice metadata — it would mint a 2048-element view over the whole
   5 | // pool. Same risk on the encode side if the input Float32Array is itself
   6 | // a sliced view. Reported as a phantom "2048 dimensions on disk" crash
   7 | // in #455 / #469 / #584 / #587.
   8 | function float32ToBase64(arr: Float32Array): string {
   9 |   return Buffer.from(arr.buffer, arr.byteOffset, arr.byteLength).toString(
  10 |     "base64",
  11 |   );
  12 | }
  13 | 
  14 | function base64ToFloat32(b64: string): Float32Array {
  15 |   const buf = Buffer.from(b64, "base64");
  16 |   return new Float32Array(
  17 |     buf.buffer,
  18 |     buf.byteOffset,
  19 |     buf.byteLength / Float32Array.BYTES_PER_ELEMENT,
  20 |   );
  21 | }
  22 | 
  23 | function cosineSimilarity(a: Float32Array, b: Float32Array): number {
  24 |   if (a.length !== b.length) return 0;
  25 |   let dot = 0;
  26 |   let normA = 0;
  27 |   let normB = 0;
  28 |   for (let i = 0; i < a.length; i++) {
  29 |     dot += a[i] * b[i];
  30 |     normA += a[i] * a[i];
  31 |     normB += b[i] * b[i];
  32 |   }
  33 |   const denom = Math.sqrt(normA) * Math.sqrt(normB);
  34 |   return denom === 0 ? 0 : dot / denom;
  35 | }
