  37 | export class VectorIndex {
  38 |   private vectors: Map<string, { embedding: Float32Array; sessionId: string }> =
  39 |     new Map();
  40 | 
  41 |   add(obsId: string, sessionId: string, embedding: Float32Array): void {
  42 |     this.vectors.set(obsId, { embedding, sessionId });
  43 |   }
  44 | 
  45 |   remove(obsId: string): void {
  46 |     this.vectors.delete(obsId);
  47 |   }
  48 | 
  49 |   search(
  50 |     query: Float32Array,
  51 |     limit = 20,
  52 |   ): Array<{ obsId: string; sessionId: string; score: number }> {
  53 |     const results: Array<{
  54 |       obsId: string;
  55 |       sessionId: string;
  56 |       score: number;
  57 |     }> = [];
  58 |     let minScore = -Infinity;
  59 | 
  60 |     for (const [obsId, entry] of this.vectors) {
  61 |       const score = cosineSimilarity(query, entry.embedding);
  62 |       if (results.length < limit) {
  63 |         results.push({ obsId, sessionId: entry.sessionId, score });
  64 |         if (results.length === limit) {
  65 |           results.sort((a, b) => a.score - b.score);
  66 |           minScore = results[0].score;
  67 |         }
  68 |       } else if (score > minScore) {
  69 |         results[0] = { obsId, sessionId: entry.sessionId, score };
  70 |         results.sort((a, b) => a.score - b.score);
  71 |         minScore = results[0].score;
  72 |       }
  73 |     }
  74 | 
  75 |     results.sort((a, b) => b.score - a.score);
  76 |     return results;
  77 |   }
  78 | 
  79 |   get size(): number {
  80 |     return this.vectors.size;
  81 |   }
